/* gamedata-w4-cooking.mjs — World 4 Kitchens + Cooking Mastery static tables/formulas,
 * extracted verbatim from N.js (v1.19-era). GENERATED by a one-off extraction script
 * (scratchpad, not committed); refresh after a major patch.
 *
 * Everything below lives in TWO dispatchers:
 *   p._customBlock_CookingR(d,b,e)     — N.js:12393-12415 — kitchens, ladles, speed/fire/luck,
 *                                        new-recipe rolls, meal cost/cap (meal cost/cap live in
 *                                        gamedata-w4-meals.mjs instead, since they're meal-scoped)
 *   m._customBlock_Summoning2(d,b,e)   — N.js:18130-18140 — Cooking MASTERY (the "yellow"/"purple"
 *                                        point systems). Note the owner function is literally
 *                                        named "Summoning2" — Cooking Mastery hides inside an
 *                                        unrelated-sounding dispatcher, same pattern documented
 *                                        elsewhere in this repo for na.Owlz/na.NinjaInfo.
 *
 * GOTCHA: there is NO separate "kitchen name" table. Kitchens are 10 unnamed numeric slots
 * (0..9) in the `Cooking` save array, created at N.js:9331 (`for(d=0;10>d;)...`); kitchen 0
 * starts unlocked (state 1), kitchens 1-9 start locked (state 0). The UI just labels them
 * "Kitchen 1".."Kitchen 10". Row layout: [0]=state, [1]=selected meal id, [2..5]=4 candidate
 * new-recipe slots, [6]=speed ladle lv, [7]=fire ladle lv, [8]=luck ladle lv, [9]=padding
 * (save-migration filler), [10]=accumulated fire toward next recipe discovery.
 *
 * GOTCHA: idleon-toolbox/parsers/world-4/cooking.ts has NO kitchen-unlock-coin-cost table at
 * all (only parses already-owned kitchens) — KITCHEN_UNLOCK_COST below has no toolbox
 * cross-check; N.js is the sole source. Everything else in this file cross-checks 0 mismatches
 * against cooking.ts.
 */

/* --------------------------------------------------------------------------------------------
 * 1. KITCHEN UNLOCK COST — CookingNewKitchenCoinCost(kitchenIdx), N.js:12415 (`CookingR`):
 *   1==b?82E5 : 2==b?75E6 : 3==b?4E8 : 4==b?8E9 : 5==b?5E10 : 6==b?213E10
 *     : 7==b?6E13 : 8==b?2E15 : 1E17
 * Kitchen 0 has no cost branch (pre-unlocked). Index 9 (and anything else) falls through to the
 * 1E17 catch-all, which is not a real purchasable price — no 10th kitchen exists in the UI.
 * Paid from `Money` at purchase (N.js:15608-15609).
 * -------------------------------------------------------------------------------------------- */
export const KITCHEN_UNLOCK_COST = {
  0: 0,          // pre-unlocked
  1: 8_200_000,
  2: 75_000_000,
  3: 400_000_000,
  4: 8_000_000_000,
  5: 50_000_000_000,
  6: 2_130_000_000_000,
  7: 60_000_000_000_000,
  8: 2_000_000_000_000_000,
  // index 9 (and any other index): 1E17 catch-all — not a real 10th kitchen, do not surface as a buyable price
};

/* --------------------------------------------------------------------------------------------
 * 2. LADLE UPGRADE COST — shared by all 3 ladle types (speed=slot 6, fire=slot 7, luck=slot 8;
 * `e` below is 0/1/2 respectively, matching `Cooking[b][6+e]`). N.js:12407-12409 (`CookingR`):
 *
 *   CookingUpgSpiceCostType(kitchenIdx b, ladleType e) = Math.floor(2*b + e)
 *     // picks WHICH spice item id is spent — one fixed spice per (kitchen, ladle-type) pair,
 *     // constant across levels.
 *
 *   CookingUpgSpiceCostQty(kitchenIdx b, ladleType e) =
 *     ( 1 + 1 / (
 *         (1 + (AlchVials.Kcosts + Labb("SigilBonus","Blank",18,0)) / 100)
 *         * (1 + 30*RandomEvent("FractalIslandBonus",2,999) / 100)
 *         * (1 + MealBonus("KitchC") / 100)
 *         * (1 + richelinDiscount / 100)      // see below
 *         * (1 + .5*Breeding("PetArenaBonus","0",7,0))
 *       )
 *     )
 *     * ( Cooking[b][6+e] + 1
 *         + Math.floor(Math.max(0, Cooking[b][6+e]-10) / 2)
 *         + Math.pow(Math.max(0, Cooking[b][6+e]-30), 1.2) )
 *     * Math.pow(1.02, Math.max(0, Cooking[b][6+e]-60));
 *
 *   richelinDiscount = GemItemsPurchased[120] > kitchenIdx ? 40 : 0
 *     // Richelin gem-shop purchase: -40%-equivalent cost reduction for kitchens BELOW the
 *     // purchased Richelin tier (threshold reused identically in CookingSPEED/CookingFIRE below).
 *
 * Purchase check compares owned spice qty `Meals[3][spiceItemId]` against CookingUpgSpiceCostQty
 * (N.js:15530, 15537-15539). Cross-checked against cooking.ts:640-654 (`parseKitchens`) — the
 * divisor bonus stack matches term-for-term (Kcosts vial, Garlic Glove sigil, Fractal Island 30%,
 * KitchC meal bonus, Richelin -40%, Pet Arena bonus); the numerator polynomial wasn't in the
 * toolbox excerpt checked but no conflicting value was found either.
 * -------------------------------------------------------------------------------------------- */
export const LADLE_COST_FORMULA = {
  spiceItemType: "Math.floor(2*kitchenIdx + ladleType)",   // ladleType: 0=speed 1=fire 2=luck
  quantityCurve: "(kitchenLv+1 + floor(max(0,kitchenLv-10)/2) + max(0,kitchenLv-30)^1.2) * 1.02^max(0,kitchenLv-60) / costReductionMultiplier",
  richelinGate: { save: "GemItemsPurchased[120]", note: "kitchenIdx < GemItemsPurchased[120] => -40% cost" },
};

/* --------------------------------------------------------------------------------------------
 * 3. COOKING SPEED — CookingSPEED(kitchenIdx b), N.js:12401-12405 (`CookingR`). Base 10, ~20
 * multiplicative bonus arms; sub-dispatchers are NOT expanded here (generic game-wide bonus
 * lookups, not W4-specific) — listed by name only:
 *
 *   CookingSPEED(b) = 10
 *     * (1 + TalentCalc(59)/100)
 *     * Math.max(1, FarmingStuffs("CropSCbonus",3,0))
 *     * Math.max(1, TalentEnh(146))
 *     * (1 + richelinFireBonus)                              // GemItemsPurchased[120]>b => +2 flat (add BEFORE the *(1+x) wrap, see note)
 *     * (1 + Summoning("VotingBonusz",13,0)/100)
 *     * (1 + Summoning("VaultUpgBonus",54,0)/100)
 *     * (1 + MealBonus("zMealFarm")*Math.ceil((Lv0[16]+1)/50)/100)
 *     * Math.max(1, AlchBubbles.MealSpdz)
 *     * Math.max(1, AtomCollider("AtomBonuses",8,0))
 *     * (1 + GamingStatType("MSA_Bonus",1,0)/100)
 *     * (1 + Cooking[b][6]/10)                                 // SPEED LADLE LEVEL — the only per-kitchen term
 *     * (1 + Sailing("ArtifactBonus",13,0)/100)
 *     * (1 + Minehead("Button_Bonuses",7,0)/100)
 *     * (1 + ArcadeBonus(28)/100)
 *     * (1 + AlchVials["6turtle"]/100)
 *     * (1 + AlchVials.MealCook/100)
 *     * (1 + (StampBonusOfTypeX("MealCook") + Math.max(0,MainframeBonus(114)))/100)
 *     * (1 + MealBonus("Mcook")/100)
 *     * (1 + StarSigns["58"]/100)
 *     * (1 + Summoning("WinBonus",15,0)/100)
 *     * (1 + Holes("MonumentROGbonuses",0,2)/100)
 *     * Math.max(1, Holes("B_UPG",56,0))
 *     * (1 + 5*RunCodeOfTypeXforThingY("CardLv","w6c1")/100)
 *     * (1 + Holes("LampBonuses",0,0)/100)
 *     * (1 + AlchVials["6CookSpd"]/100)
 *     * Math.max(1, MainframeBonus(100))
 *     * (1 + Math.min(6*RunCodeOfTypeXforThingY("CardLv","Boss4A") + (20*AchieveStatus(225)+10*AchieveStatus(224)), 100)/100)
 *     * (1 + MealBonus("KitchenEff")*Math.floor((Cooking[b][6]+Cooking[b][7]+Cooking[b][8])/10)/100);
 *   // NOTE: `richelinFireBonus` term as coded is `(1+CookinzzDN1)` where CookinzzDN1 is SET TO 2
 *   //  (not a %) when GemItemsPurchased[120]>b, else 0 — i.e. it TRIPLES the running product at
 *   //  that point in the chain, not a flat +2%. Transcribed verbatim as `(1+CookinzzDN1)` — do
 *   //  not renormalize into a %, that would misrepresent the client's actual multiplier chain.
 *
 * 4. COOKING FIRE — CookingFIRE(kitchenIdx b), N.js:12405-12407 (`CookingR`). Base 5, fewer arms:
 *
 *   CookingFIRE(b) = 5
 *     * (1 + CookinzzDN1)                                      // GemItemsPurchased[120]>b => CookinzzDN1=1 (so this term becomes *2)
 *     * (1 + Summoning("VotingBonusz",13,0)/100)
 *     * Math.max(1, AlchBubbles.MealSpdz)
 *     * Math.max(1, AtomCollider("AtomBonuses",8,0))
 *     * (1 + GamingStatType("MSA_Bonus",1,0)/100)
 *     * (1 + Cooking[b][7]/10)                                 // FIRE LADLE LEVEL
 *     * (1 + AlchVials.RecCook/100)
 *     * (1 + StampBonusOfTypeX("RecipeCook")/100)
 *     * (1 + MealBonus("Rcook")/100)
 *     * (1 + Math.min(6*RunCodeOfTypeXforThingY("CardLv","Boss4A"), 50)/100)
 *     * (1 + MealBonus("KitchenEff")*Math.floor((Cooking[b][6]+Cooking[b][7]+Cooking[b][8])/10)/100);
 *
 * Both cross-checked term-for-term against cooking.ts:523-634 (`mealSpeed`/`fireSpeed`) — 0
 * discrepancies, including the exact Richelin threshold and the Kitchen-Eff floor(sum/10) term.
 * -------------------------------------------------------------------------------------------- */

/* --------------------------------------------------------------------------------------------
 * 5. NEW-RECIPE LUCK — CookingLUCK(kitchenIdx b), N.js:12407 (`CookingR`):
 *   CookingLUCK(b) = 1 + Math.pow(5*Cooking[b][8], .85) / 100;    // Cooking[b][8] = LUCK LADLE LEVEL
 *
 * Fire-tier gate feeding the discovery roll (N.js:12409-12412):
 *   CookingFireREQ(b)          = 2 * MealINFO[min(66,nextRecipeId)][1] * Math.pow(25, max(0, nextRecipeId-66))
 *   CookingFireREQlvMULTI      = 3          // flat constant
 *   CookingFireREQlv(b)        = how many times CookingFireREQlvMULTI compounds before
 *                                 Cooking[b][10] (accumulated fire) exceeds CookingFireREQ(b)
 *
 * New-recipe discovery ROLL — CookingNewRecipeOdds, N.js:12413-12415 (`CookingR`):
 *   CookingNewRecipeOdds(kitchenIdx b, possibleRecipeId) =
 *     Meals[0][possibleRecipeId] <= 0
 *       ? RANDOlist[50][b] * CookingLUCK(b) * Math.pow(1.5, CookingFireREQlv(b))   // not yet discovered
 *       : RANDOlist[50][b];                                                        // already discovered: base roll only
 * Cross-checked: cooking.ts:637 `mealLuck = 1 + Math.pow(5*luckLv, 0.85)/100` — exact match.
 * -------------------------------------------------------------------------------------------- */
export const COOKING_LUCK_FORMULA = "1 + (5*luckLadleLv)^0.85 / 100";
export const COOKING_FIRE_REQ_MULTI = 3;

/* --------------------------------------------------------------------------------------------
 * 6. COOKING MASTERY — m._customBlock_Summoning2, N.js:18130-18140. Two point pools, NOT a
 * fixed-node "tree" in the usual sense:
 *   - "yellow" points (CookMaster[0], per-meal array) — spent 1:1 on individual meals, feeds
 *     ARM 1 (BonusMultiCook) documented in gamedata-w4-meals.mjs.
 *   - "purple" points (CookMaster[2], 6-length array) — spent on the 6 CATEGORY nodes below.
 *     This purple 6-node array IS the "category unlock table" — there is no separate one.
 *
 * Unlock gate — isMasteryUnlocked, N.js:18132:
 *   Rift[0] > 58  ||  Companions(87) > 0.1
 *   // NOTE: raw Rift index 58, but in-game flavor text (N.js:24088) and the toolbox both say
 *   // "Rift 61" as the DISPLAYED unlock tier. This is very likely a display-vs-raw-index offset
 *   // in the Rift numbering (see gamedata-w4-rift.mjs — Rift[0] is the raw counter, "Rift N" in
 *   // the UI is a different, +something mapping) — NOT reconciled here; treat Rift[0]>58 as the
 *   // save-readable gate and "Rift 61" as the player-facing number until the offset is nailed
 *   // down by whoever builds the Rift page.
 *
 * Mastery Rank EXP-to-next-rank — ExpReqCook, N.js:18133:
 *   ExpReqCook(rank) = 100 * Math.pow(2.5, rank) * Math.pow(5, Math.max(0, rank-40));
 *   // rank = CookMaster[1][0]
 *
 * Yellow-point pool size — PtsLeftCook_Y, N.js:18135:
 *   PtsLeftCook_Y = Math.max(0, Round(
 *     CookMaster[1][0] + (1+5*Companions(87)) + ResearchStuff("Grid_Bonus",190,1)
 *     - sum(CookMaster[0])
 *   ));
 *
 * Purple-point pool size — PtsLeftCook_P, N.js:18134:
 *   PtsLeftCook_P = Math.max(0, Round(
 *     CookMaster[1][0] + (1+5*Companions(87)) - sum(CookMaster[2])
 *   ));
 *
 * Mastery EXP RATE (per hour, applied N.js:15845-15848 as EXP += rate*elapsedSec/3600) —
 * ExpRateCook, N.js:18135-18136:
 *   ExpRateCook = 2
 *     * (1+BonusAmountcook(0,99)/100) * (1+BonusAmountcook(1,99)/100)
 *     * (1+BonusAmountcook(2,99)/100) * (1+BonusAmountcook(4,99)/100)   // note: category 3 (SMOKY) SKIPPED
 *     * (1 + ResearchStuff("Grid_Bonus",190,0)/100)
 *     * (1 + 40*GamingStatType("SuperBitType",68,0)/100)
 *     * (1 + BonusAmountcook(5,99)/100)
 *     * (1 + 2*Companions(87))
 *     * (1 + Holes2("Fountain_BonTOT",2,17)/100)
 *     * (1 + (AlchVials["7cookmastery"] + ArcadeBonus(69) + SaltLick(10))/100);
 * -------------------------------------------------------------------------------------------- */
export const MASTERY_UNLOCK_GATE = { rawRiftThreshold: 58, companionAltGate: 87, note: 'Rift[0]>58 OR Companions(87)>0.1; displayed in-game as "Rift 61" — offset not reconciled, see comment above' };
export const MASTERY_EXP_REQ_FORMULA = "100 * 2.5^rank * 5^max(0, rank-40)";
export const MASTERY_EXP_RATE_BASE = 2;

/** RandoListo2()[8] (coefficients) / [9] (names) — na.RandoListo2, N.js:23838 (this table is
 *  shared with W6 Farming garden-plant lore text at other indices; [8]/[9] are the Cooking
 *  Mastery purple-category rows). RankREQcook thresholds — N.js:18137,
 *  `"0 1 5 10 25 100 150 250 500".split(" ")[b]` — only indices 0..5 are consumed by the 6
 *  categories below; 150/250/500 are vestigial/unused in this dispatcher.
 *
 *  Per-category effect formula = coeff * CookMaster[2][idx] * sourceValue(idx), where
 *  sourceValue is what BonusAmountcook(idx, 0) resolves to (N.js:18137-18140, `"BonusAmountcook"==d`
 *  branch, `99==e` is the *(read total) mode used above; `e` unset/0 returns the raw sourceValue):
 *    idx 0 SALTY : sourceValue = log10(CookMaster[1][3])                — CookMaster[1][3] = cumulative
 *                   count of ladle items ever fed/sacrificed into a kitchen's fire (N.js:13024)
 *    idx 1 SPICY : sourceValue = max(0, sumOfAllCharsCookingLv - 1000)   — Lv0[10] summed over
 *                   GetPlayersUsernames, cached in DNSM.CkMst_AcLvT
 *    idx 2 SWEET : sourceValue = max(0, Meals[0][73] - 75)               — meal id 73's OWN level
 *                   (Divorce_Cake, the last meal — MEAL_INFO idx 73 in gamedata-w4-meals.mjs)
 *    idx 3 SMOKY : sourceValue = 250 * x/(25+x) where x = coeff*CookMaster[2][3] (self-referential
 *                   saturating curve, caps ~250). EXCLUDED from ExpRateCook's product (see above);
 *                   consumer at N.js:14448539 not fully resolved — flagged UNVERIFIED end-use.
 *    idx 4 SOUR  : sourceValue = sum(Ribbon[28..]) — total ribbon ranks across ALL 74 meal slots
 *    idx 5 SAVORY: sourceValue = CookMaster[1][0] + 1                    — mastery RANK + 1 (default branch)
 *  effect(idx) = coeff[idx] * CookMaster[2][idx] * sourceValue(idx)  (idx 0/1/2/4: coeff multiplies
 *  a LOG or LINEAR sourceValue directly per N.js:18137-18140; idx 3/5 have bespoke shapes above). */
export const COOKING_MASTERY_CATEGORIES = [
  { idx: 0, name: "SALTY",  coeff: 200, rankReq: 0,   source: "log10(cumulative ladle items sacrificed into kitchen fire)", feedsExpRate: true },
  { idx: 1, name: "SPICY",  coeff: 1,   rankReq: 1,   source: "max(0, sum-of-all-characters' Cooking skill level - 1000)", feedsExpRate: true },
  { idx: 2, name: "SWEET",  coeff: 30,  rankReq: 5,   source: "max(0, Meals[0][73] level - 75)  // Divorce_Cake's own level", feedsExpRate: true },
  { idx: 3, name: "SMOKY",  coeff: 10,  rankReq: 10,  source: "saturating curve 250*x/(25+x); UNVERIFIED game-facing consumer (N.js:14448539)", feedsExpRate: false },
  { idx: 4, name: "SOUR",   coeff: 2,   rankReq: 25,  source: "sum(Ribbon[28..]) // total ribbon ranks, all 74 meal slots", feedsExpRate: true },
  { idx: 5, name: "SAVORY", coeff: 20,  rankReq: 100, source: "CookMaster[1][0] + 1  // mastery rank + 1", feedsExpRate: true },
];

